class MockResponse:
    def __init__(self, status_code, payload):
        self.status_code = status_code
        self._payload = payload
    def json(self):
        return self._payload

SIGNALS = [
    {"id": "S1", "entity_id": "C001", "kind": "shared_phone"},
    {"id": "S2", "entity_id": "C002", "kind": "geo"},
]

def list_signals():
    return MockResponse(200, {"items": SIGNALS, "count": len(SIGNALS)})

r = list_signals()
print(r.status_code, r.json()["count"])

def parse_entity(payload):
    if not isinstance(payload, dict):
        raise ValueError("payload no dict")
    if "id" not in payload or "region" not in payload:
        raise ValueError("faltan id/region")
    return {"id": payload["id"], "region": payload["region"]}
print(parse_entity({"id": "C001", "region": "Lima", "extra": 1}))
try:
    parse_entity({"id": "C001"})
except ValueError as e:
    print("err", e)

STATUS_ACTION = {
    200: "use_body",
    404: "missing",
    429: "retry",
    500: "retry",
    400: "fix_client",
}
for code in [200, 400, 404, 429, 500]:
    print(code, STATUS_ACTION[code])

def paginate(pages):
    items = []
    for p in pages:
        items.extend(p)
    return items
print(paginate([['a'], ['b', 'c']]))

def should_retry(status):
    return status in {429, 503} or status >= 500
for s in [400, 404, 429, 503, 200]:
    print(s, should_retry(s))

import os
def require_token(name="API_TOKEN"):
    tok = os.environ.get(name)
    if not tok:
        raise KeyError(f"{name} missing")
    return tok
os.environ["API_TOKEN"] = "abc"
print(require_token())
try:
    del os.environ["API_TOKEN"]
    require_token()
except KeyError as e:
    print(e)

def parse_json_body(text):
    import json
    try:
        return json.loads(text), True
    except json.JSONDecodeError:
        return None, False
print(parse_json_body('{"ok": true}'))
print(parse_json_body('nope'))

def min_provenance(url, status, cache_hit):
    return {
        "source_url": url,
        "fetched_at": "2026-07-20T00:00:00Z",
        "status_code": status,
        "cache_hit": cache_hit,
    }
print(min_provenance("https://api.example.com/x", 200, False))

REQUIRED = {"lat", "lon", "provider"}
def assert_geo_contract(d):
    missing = sorted(REQUIRED - set(d.keys()))
    if missing:
        return f"missing keys: {missing}"
    return "ok"
print(assert_geo_contract({"lat": 1, "lon": 2, "provider": "mock"}))
print(assert_geo_contract({"lat": 1, "provider": "mock"}))

def fetch_with_fallback(status, local_body):
    if status >= 500:
        return (local_body, "offline")
    if status == 200:
        return ({"online": True}, "online")
    return (local_body, "offline")
print(fetch_with_fallback(500, {"cached": 1}))
print(fetch_with_fallback(200, {"cached": 1}))

def normalize_address(s):
    return " ".join(s.strip().split())
print(normalize_address("  Jr.  de  la  Unión   100  "))

class MockGeocoder:
    DB = {"Lima": (-12.0464, -77.0428), "Arequipa": (-16.4090, -71.5375)}
    def geocode(self, city):
        if city not in self.DB:
            return None
        lat, lon = self.DB[city]
        return {"city": city, "lat": lat, "lon": lon, "provider": "authorized_mock"}
g = MockGeocoder()
print(g.geocode("Lima")["lat"])
print(g.geocode("Iquitos"))

ALLOWED = {"address", "city", "country"}
def allowed_for_public_geocoder(payload):
    return set(payload.keys()) <= ALLOWED
print(allowed_for_public_geocoder({"address": "x", "city": "Lima"}))
print(allowed_for_public_geocoder({"address": "x", "document_id": "DNI"}))

def valid_lat_lon(lat, lon):
    return -90 <= lat <= 90 and -180 <= lon <= 180
print(valid_lat_lon(-12.04, -77.04), valid_lat_lon(100, 0))

def as_relationship_signal(km):
    return {"type": "geo_distance_km", "value": km, "not_a_verdict": True}
print(as_relationship_signal(1.2))
